function getAuthStateKey(user) {
    return user?.uid
        ? `${user.uid}|${user.email || ''}|${user.displayName || ''}`
        : 'guest';
}

function persistGuestOrders() {
    localStorage.setItem(GUEST_ORDERS_STORAGE_KEY, JSON.stringify(appState.guestOrders));
}

function getOrderDisplayId(order) {
    return order?.orderNumber || order?.id || '-';
}

function getOrderItemQty(item) {
    const quantity = Number(item?.qty ?? item?.quantity ?? 1);
    return Number.isFinite(quantity) && quantity > 0 ? quantity : 1;
}

function setActiveOrders(nextOrders, source = 'guest') {
    appState.orders = Array.isArray(nextOrders) ? nextOrders : [];
    appState.ordersSource = source;
    visibleRecentOrdersCount = RECENT_ORDERS_PAGE_SIZE;
    updateOrdersContextCopy();
    renderOrders();
}

function getAccountDisplayName(user = appState.user) {
    if (user?.displayName) return user.displayName;
    if (user?.email) return String(user.email).split('@')[0];
    return 'حساب الزائر';
}

function setAccountFeedback(message = '', type = 'info') {
    const feedback = document.getElementById('auth-feedback');
    if (!feedback) return;

    if (!message) {
        feedback.hidden = true;
        feedback.textContent = '';
        return;
    }

    const colors = {
        info: 'var(--text-secondary)',
        success: 'var(--accent-green)',
        error: 'var(--accent-red)'
    };

    feedback.hidden = false;
    feedback.textContent = message;
    feedback.style.color = colors[type] || colors.info;
}

function setButtonBusy(button, isBusy, busyText) {
    if (!button) return;

    if (isBusy) {
        button.dataset.originalHtml = button.innerHTML;
        button.innerHTML = `<i class="fa-solid fa-circle-notch fa-spin"></i> <span>${busyText}</span>`;
        button.disabled = true;
        return;
    }

    button.innerHTML = button.dataset.originalHtml || button.innerHTML;
    button.disabled = false;
}

function hasPendingCheckoutLoginReturn() {
    try {
        return sessionStorage.getItem(CHECKOUT_LOGIN_RETURN_KEY) === '1';
    } catch {
        return false;
    }
}

function setPendingCheckoutLoginReturn() {
    try {
        sessionStorage.setItem(CHECKOUT_LOGIN_RETURN_KEY, '1');
    } catch {}
}

function clearPendingCheckoutLoginReturn() {
    try {
        sessionStorage.removeItem(CHECKOUT_LOGIN_RETURN_KEY);
    } catch {}
}

function setPendingCheckoutAutoSubmitAfterLogin(payload = {}) {
    checkoutAutoSubmitHandled = false;
    safeSessionStorageSet(CHECKOUT_AUTO_SUBMIT_AFTER_LOGIN_KEY, JSON.stringify({
        ...payload,
        createdAt: Date.now()
    }));
}

function getPendingCheckoutAutoSubmitAfterLogin() {
    const rawValue = safeSessionStorageGet(CHECKOUT_AUTO_SUBMIT_AFTER_LOGIN_KEY);
    if (!rawValue) return null;

    try {
        const parsedValue = JSON.parse(rawValue);
        return parsedValue && typeof parsedValue === 'object' ? parsedValue : null;
    } catch {
        return null;
    }
}

function hasPendingCheckoutAutoSubmitAfterLogin() {
    return Boolean(getPendingCheckoutAutoSubmitAfterLogin());
}

function clearPendingCheckoutAutoSubmitAfterLogin() {
    safeSessionStorageRemove(CHECKOUT_AUTO_SUBMIT_AFTER_LOGIN_KEY);
}

function buildWhatsAppUrl(message = '', phoneNumber = SUPPORT_WHATSAPP_NUMBER) {
    const normalizedPhone = String(phoneNumber || '').replace(/\D/g, '') || SUPPORT_WHATSAPP_NUMBER;
    const baseUrl = `https://wa.me/${normalizedPhone}`;
    return message ? `${baseUrl}?text=${encodeURIComponent(message)}` : baseUrl;
}

function buildSupportWhatsAppMessage(context = 'support') {
    if (context === 'direct-support') {
        return 'مرحباً، أحتاج إلى دعم مباشر بخصوص طلب أو خدمة لدى زارز.';
    }

    return 'مرحباً، أريد الاستفسار عن إحدى خدمات زارز وأحتاج إلى المتابعة عبر واتساب.';
}

function buildOrderWhatsAppMessage({
    orderNum,
    customerName,
    customerPhone,
    paymentMethodLabel,
    transactionLast4 = '',
    detailsStr,
    totalStr,
    orderSource = 'guest'
} = {}) {
    const orderSourceLabel = orderSource === 'account' ? 'من الحساب بعد تسجيل الدخول' : 'كزائر';
    return [
        '*طلب جديد*',
        `*رقم الطلب:* ${orderNum}`,
        `*اسم العميل:* ${customerName}`,
        `*رقم الهاتف:* ${customerPhone}`,
        `*نوع الإكمال:* ${orderSourceLabel}`,
        `*طريقة الدفع:* ${paymentMethodLabel}`,
        transactionLast4 ? `*آخر 4 أرقام من التحويل:* ${transactionLast4}` : '',
        '',
        '*تفاصيل الطلب:*',
        detailsStr,
        '',
        `*الإجمالي:* ${totalStr}`
    ].filter(Boolean).join('\n');
}

window.openSupportWhatsApp = function(context = 'support') {
    window.location.assign(buildWhatsAppUrl(buildSupportWhatsAppMessage(context)));
};

function queuePostNavigationToast(message, type = 'info') {
    if (!message) return;

    safeSessionStorageSet(POST_NAVIGATION_TOAST_KEY, JSON.stringify({
        message,
        type,
        createdAt: Date.now()
    }));
}

function consumePostNavigationToast() {
    const rawValue = safeSessionStorageGet(POST_NAVIGATION_TOAST_KEY);
    if (!rawValue) return null;

    safeSessionStorageRemove(POST_NAVIGATION_TOAST_KEY);

    try {
        const parsedValue = JSON.parse(rawValue);
        return parsedValue && typeof parsedValue === 'object' ? parsedValue : null;
    } catch {
        return null;
    }
}

function queueAccountOrdersScroll() {
    safeSessionStorageSet(ACCOUNT_SCROLL_TO_ORDERS_KEY, '1');
}

function consumeAccountOrdersScroll() {
    const shouldScroll = safeSessionStorageGet(ACCOUNT_SCROLL_TO_ORDERS_KEY) === '1';
    safeSessionStorageRemove(ACCOUNT_SCROLL_TO_ORDERS_KEY);
    return shouldScroll;
}

function consumeGoogleRedirectOutcome() {
    const rawValue = safeSessionStorageGet(GOOGLE_REDIRECT_RESULT_KEY);
    if (!rawValue) return null;

    safeSessionStorageRemove(GOOGLE_REDIRECT_RESULT_KEY);

    try {
        const parsedValue = JSON.parse(rawValue);
        return parsedValue && typeof parsedValue === 'object' ? parsedValue : null;
    } catch {
        return null;
    }
}

function flushPendingPostNavigationToast() {
    const pendingToast = consumePostNavigationToast();
    if (!pendingToast?.message) return;

    window.setTimeout(() => {
        showToast(pendingToast.message, pendingToast.type || 'info');
    }, 120);
}

function shouldPrioritizeGuestOrders() {
    return !appState.user && appState.ordersSource === 'guest' && appState.orders.length > 0;
}

function applyAccountOrdersPriorityLayout() {
    const container = document.getElementById('account-content');
    const ordersSection = document.getElementById('account-orders-section');

    if (!container || !ordersSection) return;

    const shouldPrioritize = shouldPrioritizeGuestOrders();
    container.classList.toggle('guest-orders-priority', shouldPrioritize);

    if (!shouldPrioritize || !shouldScrollAccountOrdersOnLoad) return;

    shouldScrollAccountOrdersOnLoad = false;
    window.setTimeout(() => {
        ordersSection.scrollIntoView({
            behavior: 'smooth',
            block: 'start'
        });
    }, 160);
}

function handlePendingGoogleRedirectOutcome() {
    if (!pendingGoogleRedirectOutcome) return;

    const outcome = pendingGoogleRedirectOutcome;
    pendingGoogleRedirectOutcome = null;

    if (outcome.status === 'success' && appState.user) {
        setAccountFeedback(ARABIC_UI_TEXT.authGoogleSuccess, 'success');
        if (!maybeResumeCheckoutAfterAuth()) {
            showToast(ARABIC_UI_TEXT.authGoogleSuccess, 'success');
        }
        return;
    }

    const message = outcome.message || ARABIC_UI_TEXT.authGoogleRedirectCancelled;
    setAccountFeedback(message, 'error');
    showToast(message, 'error');
}

function shouldDelayAccountUiUntilBootstrap() {
    return getCurrentStaticPageView() === 'account' && accountInitialLoadPending;
}

function shouldKeepAccountOrdersLoading() {
    return getCurrentStaticPageView() === 'account' && (accountInitialLoadPending || accountOrdersLoadPending);
}

function setAccountLoadingState({
    authLoading = shouldDelayAccountUiUntilBootstrap(),
    ordersLoading = shouldKeepAccountOrdersLoading()
} = {}) {
    const accountContent = document.getElementById('account-content');
    const authLoadingElement = document.getElementById('account-auth-loading');
    const ordersSection = document.getElementById('account-orders-section');
    const ordersLoadingElement = document.getElementById('account-orders-loading');
    const ordersBody = document.getElementById('account-orders-body');

    if (accountContent) {
        accountContent.dataset.authState = authLoading ? 'loading' : 'ready';
        accountContent.setAttribute('aria-busy', String(authLoading || ordersLoading));
    }

    if (authLoadingElement) authLoadingElement.hidden = !authLoading;
    if (ordersSection) ordersSection.hidden = authLoading;
    if (ordersLoadingElement) ordersLoadingElement.hidden = authLoading || !ordersLoading;
    if (ordersBody) ordersBody.hidden = authLoading || ordersLoading;
}

function getGuestAccountPromptMessage() {
    return hasPendingCheckoutLoginReturn()
        ? 'سجل دخولك ثم عد لإتمام طلبك.'
        : ARABIC_UI_TEXT.authRequiredForSync;
}

function maybeResumeCheckoutAfterAuth() {
    if (!hasPendingCheckoutLoginReturn()) return false;

    clearPendingCheckoutLoginReturn();

    if (appState.cart.length === 0) return false;

    window.setTimeout(() => {
        const resumeMessage = hasPendingCheckoutAutoSubmitAfterLogin()
            ? 'تم تسجيل الدخول. جارٍ متابعة طلبك الآن.'
            : 'تم تسجيل الدخول. يمكنك الآن إكمال طلبك.';
        showToast(resumeMessage, 'success');
        navigateTo('checkout');
    }, 120);

    return true;
}

function maybeAutoSubmitPendingCheckoutAfterLogin() {
    if (checkoutAutoSubmitHandled) return false;
    if (getCurrentStaticPageView() !== 'checkout') return false;
    if (!appState.user || appState.cart.length === 0) return false;

    const pendingCheckoutAutoSubmit = getPendingCheckoutAutoSubmitAfterLogin();
    if (!pendingCheckoutAutoSubmit) return false;

    const checkoutForm = document.getElementById('checkoutForm');
    if (!checkoutForm) return false;

    checkoutAutoSubmitHandled = true;
    clearPendingCheckoutAutoSubmitAfterLogin();

    window.setTimeout(() => {
        showToast('جارٍ إكمال طلبك...', 'info');
        window.processOrder();
    }, 220);

    return true;
}

async function promptCheckoutAccountChoice() {
    if (appState.user) return 'guest';

    const modalRoot = document.getElementById('modal-root');
    if (!modalRoot) return 'guest';

    return new Promise((resolve) => {
        const closePrompt = (choice = 'cancel') => {
            document.removeEventListener('keydown', handleEscape);
            modalRoot.innerHTML = '';
            document.body.style.overflow = '';
            resolve(choice);
        };

        const handleEscape = (event) => {
            if (event.key !== 'Escape') return;
            event.preventDefault();
            closePrompt('cancel');
        };

        modalRoot.innerHTML = `
            <div class="modal-overlay" id="checkout-auth-choice-modal">
                <div class="modal-content" role="dialog" aria-modal="true" aria-labelledby="checkout-auth-choice-title" style="max-width: 520px; padding: 2rem;">
                    <button type="button" id="checkout-auth-choice-close" aria-label="إغلاق" style="width: 42px; height: 42px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.04); color: var(--text-primary); display: inline-flex; align-items: center; justify-content: center; cursor: pointer; margin-inline-start: auto; margin-bottom: 1rem;">
                        <i class="fa-solid fa-xmark"></i>
                    </button>
                    <div style="display: grid; gap: 1rem; text-align: center;">
                        <div style="width: 64px; height: 64px; margin: 0 auto; border-radius: 18px; background: linear-gradient(135deg, rgba(255,0,122,0.18), rgba(0,212,255,0.18)); display: flex; align-items: center; justify-content: center; color: var(--text-primary); font-size: 1.4rem;">
                            <i class="fa-solid fa-user-check"></i>
                        </div>
                        <div>
                            <h3 id="checkout-auth-choice-title" style="margin: 0 0 0.45rem; font-size: 1.5rem;">كيف تريد إكمال الطلب؟</h3>
                            <p style="margin: 0; color: var(--text-secondary); font-size: 0.98rem; line-height: 1.8;">
                                يمكنك تسجيل الدخول أولاً أو إكمال الطلب الآن كزائر.
                            </p>
                        </div>
                        <div style="display: grid; gap: 0.85rem; margin-top: 0.35rem;">
                            <button type="button" id="checkout-auth-choice-login" class="btn btn-primary" style="width: 100%; padding: 0.95rem 1.2rem;">
                                <i class="fa-solid fa-right-to-bracket"></i>
                                <span>تسجيل الدخول</span>
                            </button>
                            <button type="button" id="checkout-auth-choice-guest" class="btn btn-secondary" style="width: 100%; padding: 0.95rem 1.2rem;">
                                <i class="fa-regular fa-user"></i>
                                <span>الإكمال كزائر</span>
                            </button>
                        </div>
                        <p style="margin: 0.25rem 0 0; color: var(--text-secondary); font-size: 0.9rem;">
                            إذا سجلت الدخول سيظهر الطلب داخل حسابك بعد الإرسال.
                        </p>
                    </div>
                </div>
            </div>
        `;

        const overlay = modalRoot.querySelector('#checkout-auth-choice-modal');
        const closeBtn = modalRoot.querySelector('#checkout-auth-choice-close');
        const loginBtn = modalRoot.querySelector('#checkout-auth-choice-login');
        const guestBtn = modalRoot.querySelector('#checkout-auth-choice-guest');

        overlay?.addEventListener('click', (event) => {
            if (event.target === overlay) {
                closePrompt('cancel');
            }
        });
        closeBtn?.addEventListener('click', () => closePrompt('cancel'));
        loginBtn?.addEventListener('click', () => closePrompt('login'));
        guestBtn?.addEventListener('click', () => closePrompt('guest'));

        document.addEventListener('keydown', handleEscape);
        document.body.style.overflow = 'hidden';

        window.requestAnimationFrame(() => {
            loginBtn?.focus();
        });
    });
}

function updateAuthModeUI(mode = currentAuthMode) {
    currentAuthMode = mode === 'register' ? 'register' : 'signin';

    const loginTab = document.getElementById('auth-tab-login');
    const registerTab = document.getElementById('auth-tab-register');
    const nameField = document.getElementById('auth-name-group');
    const confirmField = document.getElementById('auth-confirm-group');
    const submitLabel = document.getElementById('auth-submit-label');
    const title = document.getElementById('auth-panel-title');
    const subtitle = document.getElementById('account-sync-hint');
    const resetBtn = document.getElementById('auth-reset-btn');

    const isRegister = currentAuthMode === 'register';
    const activeStyles = {
        background: 'linear-gradient(135deg,var(--accent-primary),var(--accent-secondary))',
        color: '#fff'
    };
    const inactiveStyles = {
        background: 'transparent',
        color: 'var(--text-secondary)'
    };

    if (loginTab) {
        loginTab.hidden = false;
        Object.assign(loginTab.style, isRegister ? inactiveStyles : activeStyles);
    }
    if (registerTab) {
        registerTab.hidden = false;
        Object.assign(registerTab.style, isRegister ? activeStyles : inactiveStyles);
    }
    if (nameField) nameField.hidden = !isRegister;
    if (confirmField) confirmField.hidden = !isRegister;
    if (resetBtn) resetBtn.hidden = isRegister;
    if (submitLabel) submitLabel.textContent = isRegister ? 'إنشاء حساب' : 'تسجيل الدخول';
    if (title) title.textContent = isRegister ? 'إنشاء حساب' : 'تسجيل الدخول';
    if (subtitle && !appState.user) {
        subtitle.textContent = isRegister ? 'أنشئ حسابك للمتابعة' : 'أدخل بياناتك للمتابعة';
    }

    const passwordInput = document.getElementById('auth-password');
    if (passwordInput) {
        passwordInput.autocomplete = isRegister ? 'new-password' : 'current-password';
    }
}

function updateOrdersContextCopy() {
    const modeNote = document.getElementById('orders-mode-note');
    const emptyText = document.getElementById('orders-empty-text');
    const summaryNote = document.getElementById('orders-summary-note');
    const showGuestOrdersNote = shouldPrioritizeGuestOrders();

    if (modeNote) {
        modeNote.hidden = !showGuestOrdersNote;
        modeNote.textContent = showGuestOrdersNote
            ? 'هذه طلباتك كزائر وتظهر هنا أولاً. يمكنك تسجيل الدخول لاحقاً للمتابعة من حسابك.'
            : '';
    }

    if (emptyText) {
        emptyText.textContent = 'لا توجد طلبات حتى الآن.';
    }

    if (summaryNote && appState.orders.length === 0) {
        summaryNote.hidden = false;
        summaryNote.textContent = appState.user
            ? 'ستظهر طلبات هذا الحساب هنا.'
            : 'ستظهر أحدث طلباتك هنا.';
    }

    applyAccountOrdersPriorityLayout();
}

function renderAccountAvatar() {
    const avatar = document.getElementById('acc-avatar-placeholder');
    if (!avatar) return;

    avatar.innerHTML = '';

    if (!appState.user) {
        avatar.innerHTML = '<i class="fa-solid fa-user"></i>';
        return;
    }

    if (appState.user.photoURL) {
        const img = document.createElement('img');
        img.src = appState.user.photoURL;
        img.alt = getAccountDisplayName();
        img.style.width = '100%';
        img.style.height = '100%';
        img.style.objectFit = 'cover';
        img.style.borderRadius = '50%';
        avatar.appendChild(img);
        return;
    }

    const fallback = document.createElement('span');
    fallback.textContent = Array.from(getAccountDisplayName().trim())[0] || 'Z';
    fallback.style.fontWeight = '800';
    fallback.style.fontFamily = 'var(--font-heading)';
    fallback.style.fontSize = '1.4rem';
    fallback.style.color = 'var(--text-primary)';
    avatar.appendChild(fallback);
}

function updateAccountProfileUI() {
    const user = appState.user;
    const isPending = shouldDelayAccountUiUntilBootstrap();
    const guestPanel = document.getElementById('auth-guest-panel');
    const userPanel = document.getElementById('auth-user-panel');
    const accName = document.getElementById('acc-name');
    const accEmail = document.getElementById('acc-email');
    const userGreeting = document.getElementById('auth-user-greeting');
    const userMeta = document.getElementById('auth-user-meta');
    const authEmail = document.getElementById('auth-email');

    setAccountLoadingState();

    if (accName) {
        accName.textContent = user ? getAccountDisplayName(user) : 'حساب الزائر';
    }

    if (accEmail) {
        accEmail.textContent = user
            ? (user.email || 'تم تسجيل الدخول إلى حسابك')
            : 'يمكنك تصفح الخدمات والطلبات بسهولة';
    }

    if (guestPanel) guestPanel.hidden = isPending || Boolean(user);
    if (userPanel) userPanel.hidden = isPending || !user;

    if (isPending) return;

    if (userGreeting) {
        userGreeting.textContent = user ? `أهلاً ${getAccountDisplayName(user)}` : '';
    }

    if (userMeta) {
        const metaText = user ? (user.email || '') : '';
        userMeta.textContent = metaText;
        userMeta.hidden = !metaText;
    }

    if (authEmail && user?.email && !authEmail.value) {
        authEmail.value = user.email;
    }

    renderAccountAvatar();
    updateOrdersContextCopy();
}

async function refreshOrdersForCurrentContext({ silent = false } = {}) {
    const shouldManageOrdersLoading = hasAccountUiContext();

    if (!appState.user) {
        accountOrdersLoadPending = false;
        setAccountLoadingState();
        setActiveOrders([...appState.guestOrders], 'guest');
        if (!silent) {
            setAccountFeedback(getGuestAccountPromptMessage(), 'info');
        }
        return appState.orders;
    }

    const authApi = getAuthApi();

    if (!authApi || typeof authApi.loadOrdersForCurrentUser !== 'function') {
        accountOrdersLoadPending = false;
        setAccountLoadingState();
        const error = new Error('Auth API is not available.');
        error.userMessage = ARABIC_UI_TEXT.authLoadOrdersFailed;
        throw error;
    }

    if (shouldManageOrdersLoading) {
        accountOrdersLoadPending = true;
        setAccountLoadingState();
    }

    const remoteOrders = await authApi.loadOrdersForCurrentUser();
    accountOrdersLoadPending = false;
    setAccountLoadingState();
    setActiveOrders(remoteOrders, 'remote');

    if (!silent) {
        setAccountFeedback('تم تحديث الطلبات.', 'success');
    }

    return remoteOrders;
}

async function handleAuthStateChange(user, { silent = true } = {}) {
    const nextAuthStateKey = getAuthStateKey(user);
    const authStateChanged = nextAuthStateKey !== lastHandledAuthStateKey;
    lastHandledAuthStateKey = nextAuthStateKey;

    appState.user = user || null;
    accountInitialLoadPending = false;
    updateAccountProfileUI();
    maybeAutoSubmitPendingCheckoutAfterLogin();

    if (!authStateChanged && silent) {
        return;
    }

    if (!hasAccountUiContext()) {
        if (!appState.user) {
            appState.orders = [...appState.guestOrders];
            appState.ordersSource = 'guest';
        }
        return;
    }

    try {
        await refreshOrdersForCurrentContext({ silent });
        if (!appState.user && silent) {
            setAccountFeedback(getGuestAccountPromptMessage(), 'info');
        }
    } catch (error) {
        console.error(error);
        accountOrdersLoadPending = false;
        setAccountLoadingState();
        if (appState.user) {
            setActiveOrders([], 'remote');
        } else {
            setActiveOrders([...appState.guestOrders], 'guest');
        }
        setAccountFeedback(error?.userMessage || ARABIC_UI_TEXT.authLoadOrdersFailed, 'error');
        if (!silent) {
            showToast(error?.userMessage || ARABIC_UI_TEXT.authLoadOrdersFailed, 'error');
        }
    }

    handlePendingGoogleRedirectOutcome();
}

function bindAuthStateEvents() {
    if (authStateEventsBound) return;
    authStateEventsBound = true;

    window.addEventListener('zarz-auth-changed', (event) => {
        handleAuthStateChange(event.detail?.user, { silent: true });
    });
}

function bindAccountAuthUI() {
    if (accountAuthUiBound) return;
    accountAuthUiBound = true;

    const authForm = document.getElementById('auth-form');
    const loginTab = document.getElementById('auth-tab-login');
    const registerTab = document.getElementById('auth-tab-register');
    const googleBtn = document.getElementById('auth-google-btn');
    const resetBtn = document.getElementById('auth-reset-btn');
    const signOutBtn = document.getElementById('account-signout-btn');
    const refreshBtn = document.getElementById('account-refresh-orders-btn');

    if (loginTab) {
        loginTab.addEventListener('click', () => updateAuthModeUI('signin'));
    }

    if (registerTab) {
        registerTab.addEventListener('click', () => updateAuthModeUI('register'));
    }

    if (authForm) {
        authForm.addEventListener('submit', async (event) => {
            event.preventDefault();

            const authApi = getAuthApi();
            if (!authApi) {
                showToast('الخدمة غير متاحة الآن. حاول مرة أخرى بعد قليل.', 'error');
                return;
            }

            const nameInput = document.getElementById('auth-name');
            const emailInput = document.getElementById('auth-email');
            const passwordInput = document.getElementById('auth-password');
            const confirmInput = document.getElementById('auth-confirm-password');
            const submitBtn = document.getElementById('auth-submit-btn');
            const email = String(emailInput?.value || '').trim();
            const password = String(passwordInput?.value || '');
            const name = String(nameInput?.value || '').trim();
            const confirmPassword = String(confirmInput?.value || '');
            const isRegister = currentAuthMode === 'register';

            if (!email || !password) {
                showToast('يرجى إدخال البريد الإلكتروني وكلمة المرور.', 'error');
                return;
            }

            if (isRegister && name.length < 2) {
                showToast('يرجى إدخال اسم واضح مكوّن من حرفين على الأقل.', 'error');
                return;
            }

            if (password.length < 6) {
                showToast('كلمة المرور يجب أن تتكون من 6 أحرف أو أكثر.', 'error');
                return;
            }

            if (isRegister && password !== confirmPassword) {
                showToast('تأكيد كلمة المرور غير مطابق.', 'error');
                return;
            }

            try {
                setButtonBusy(submitBtn, true, isRegister ? 'جارٍ إنشاء الحساب...' : 'جارٍ تسجيل الدخول...');

                if (isRegister) {
                    await authApi.registerWithEmail({ name, email, password });
                    setAccountFeedback('تم إنشاء الحساب بنجاح.', 'success');
                    if (!maybeResumeCheckoutAfterAuth()) {
                        showToast(ARABIC_UI_TEXT.authRegisterSuccess, 'success');
                    }
                    updateAuthModeUI('signin');
                } else {
                    await authApi.signInWithEmail({ email, password });
                    setAccountFeedback('تم تسجيل الدخول بنجاح.', 'success');
                    if (!maybeResumeCheckoutAfterAuth()) {
                        showToast(ARABIC_UI_TEXT.authSignInSuccess, 'success');
                    }
                }

                authForm.reset();
            } catch (error) {
                console.error(error);
                setAccountFeedback(error?.userMessage || 'تعذر تنفيذ العملية المطلوبة الآن.', 'error');
                showToast(error?.userMessage || 'تعذر تنفيذ العملية المطلوبة الآن.', 'error');
            } finally {
                setButtonBusy(submitBtn, false);
            }
        });
    }

    if (googleBtn) {
        googleBtn.addEventListener('click', async () => {
            const authApi = getAuthApi();
            if (!authApi) {
                showToast('الخدمة غير متاحة الآن. حاول مرة أخرى بعد قليل.', 'error');
                return;
            }

            try {
                setButtonBusy(googleBtn, true, 'جارٍ فتح Google...');
                const googleSignInResult = await authApi.signInWithGoogle();
                if (googleSignInResult?.pendingRedirect) {
                    setAccountFeedback(ARABIC_UI_TEXT.authGoogleRedirectProgress, 'info');
                    return;
                }
                setAccountFeedback('تم تسجيل الدخول عبر Google.', 'success');
                if (!maybeResumeCheckoutAfterAuth()) {
                    showToast(ARABIC_UI_TEXT.authGoogleSuccess, 'success');
                }
            } catch (error) {
                console.error(error);
                setAccountFeedback(error?.userMessage || 'تعذر تسجيل الدخول عبر Google.', 'error');
                showToast(error?.userMessage || 'تعذر تسجيل الدخول عبر Google.', 'error');
            } finally {
                setButtonBusy(googleBtn, false);
            }
        });
    }

    if (resetBtn) {
        resetBtn.addEventListener('click', async () => {
            const authApi = getAuthApi();
            const email = String(document.getElementById('auth-email')?.value || '').trim();

            if (!authApi) {
                showToast('الخدمة غير متاحة الآن. حاول مرة أخرى بعد قليل.', 'error');
                return;
            }

            if (!email) {
                showToast('أدخل بريدك الإلكتروني أولًا ثم أعد المحاولة.', 'error');
                return;
            }

            try {
                setButtonBusy(resetBtn, true, 'جارٍ الإرسال...');
                await authApi.sendPasswordReset(email);
                setAccountFeedback(ARABIC_UI_TEXT.authResetSent, 'success');
                showToast(ARABIC_UI_TEXT.authResetSent, 'success');
            } catch (error) {
                console.error(error);
                setAccountFeedback(error?.userMessage || 'تعذر إرسال رابط إعادة التعيين.', 'error');
                showToast(error?.userMessage || 'تعذر إرسال رابط إعادة التعيين.', 'error');
            } finally {
                setButtonBusy(resetBtn, false);
            }
        });
    }

    if (signOutBtn) {
        signOutBtn.addEventListener('click', async () => {
            const authApi = getAuthApi();
            if (!authApi) {
                showToast('الخدمة غير متاحة الآن. حاول مرة أخرى بعد قليل.', 'error');
                return;
            }

            try {
                setButtonBusy(signOutBtn, true, 'جارٍ تسجيل الخروج...');
                await authApi.signOut();
                setAccountFeedback(getGuestAccountPromptMessage(), 'info');
                showToast(ARABIC_UI_TEXT.authSignOutSuccess, 'success');
            } catch (error) {
                console.error(error);
                setAccountFeedback(error?.userMessage || 'تعذر تسجيل الخروج الآن.', 'error');
                showToast(error?.userMessage || 'تعذر تسجيل الخروج الآن.', 'error');
            } finally {
                setButtonBusy(signOutBtn, false);
            }
        });
    }

    if (refreshBtn) {
        refreshBtn.addEventListener('click', async () => {
            try {
                setButtonBusy(refreshBtn, true, 'جارٍ التحديث...');
                await refreshOrdersForCurrentContext();
                showToast('تم تحديث طلبات الحساب.', 'success');
            } catch (error) {
                console.error(error);
                setAccountFeedback(error?.userMessage || ARABIC_UI_TEXT.authLoadOrdersFailed, 'error');
                showToast(error?.userMessage || ARABIC_UI_TEXT.authLoadOrdersFailed, 'error');
            } finally {
                setButtonBusy(refreshBtn, false);
            }
        });
    }

    updateAuthModeUI('signin');
    updateAccountProfileUI();
}

function localizeChoice(value) {
    if (value && typeof value === 'object') {
        return value.ar || value.en || '';
    }
    return value || '';
}

function getProductCopy(product) {
    return { title: product.title, desc: product.desc };
}

function getProductMeta(product) {
    const meta = productDisplayMeta[product.id] || {};
    return {
        reviewCount: meta.reviewCount || Math.max(24, Math.round(Number(product.rating || 4.8) * 32)),
        stock: product.outOfStock ? 0 : (meta.stock || 18),
        variationGroups: meta.variationGroups || [],
        imagePosition: meta.imagePosition || {}
    };
}

function getProductImageStyleAttr(product, context = 'card') {
    const meta = getProductMeta(product);
    const position = meta.imagePosition[context];

    if (!position) return '';

    const cssVarName = context === 'quickView'
        ? '--quick-view-image-position'
        : context === 'details'
            ? '--details-image-position'
            : '--product-image-position';

    return ` style="${cssVarName}: ${position};"`;
}

function getProductVariationGroups(product) {
    const meta = getProductMeta(product);
    const groups = [...meta.variationGroups];

    if (product.details && Array.isArray(product.details.options) && product.details.options.length > 0) {
        groups.unshift({
            id: 'package',
            label: { ar: 'الباقة', en: 'Package' },
            options: product.details.options.map((opt, index) => ({
                id: `package-${index}`,
                label: opt.label,
                price: opt.price
            }))
        });
    }

    return groups;
}

function getStockText(product, meta) {
    return product.outOfStock
        ? t('Out of Stock', 'نفذت الكمية')
        : t(`${meta.stock} in stock`, `متوفر ${meta.stock}`);
}

function getPaymentMethodLabel(method) {
    if (method === 'bankak') return t('Bankak transfer', 'تحويل بنكك');
    if (method === 'whatsapp') return t('WhatsApp follow-up', 'متابعة عبر واتساب');
    return method || '';
}

function isWishlisted(productId) {
    return appState.wishlist.includes(productId);
}

const PRODUCT_ROUTE_SLUGS = {
    sm1: 'متابعين-انستجرام',
    sm2: 'متابعين-تيك-توك',
    sm3: 'متابعين-فيسبوك',
    g1: 'شدات-ببجي-موبايل',
    g2: 'جواهر-فري-فاير',
    sub1: 'شات-جي-بي-تي-بلس-شهر',
    sub2: 'جيميني-برو-شهر',
    web1: 'انشاء-متجر-الكتروني',
    web2: 'تعديل-المواقع',
    web3: 'تاجير-موقع-او-متجر-الكتروني'
};

function normalizeProductSlug(slug) {
    const rawSlug = String(slug || '').trim();

    if (!rawSlug) return '';

    try {
        return decodeURIComponent(rawSlug);
    } catch {
        return rawSlug;
    }
}

const PRODUCT_SLUG_TO_ID = Object.fromEntries(
    Object.entries(PRODUCT_ROUTE_SLUGS)
        .map(([productId, slug]) => [normalizeProductSlug(slug).toLowerCase(), productId])
);

const STATIC_PAGE_ROUTES = {
    home: '/',
    store: '/products/',
    account: '/account/',
    contact: '/contact/',
    terms: '/terms/'
};

const STATIC_PAGE_URLS = {
    home: 'https://zarzofficial.com/',
    store: 'https://zarzofficial.com/products/',
    account: 'https://zarzofficial.com/account/',
    contact: 'https://zarzofficial.com/contact/',
    terms: 'https://zarzofficial.com/terms/'
};

function getProductSlug(productId) {
    return PRODUCT_ROUTE_SLUGS[productId] || '';
}

function getProductIdBySlug(slug) {
    return PRODUCT_SLUG_TO_ID[normalizeProductSlug(slug).toLowerCase()] || '';
}

function normalizeRoutePath(pathname = window.location.pathname) {
    if (!pathname) return '/';

    let normalized = pathname.replace(/\/{2,}/g, '/');
    if (!normalized.startsWith('/')) normalized = `/${normalized}`;
    if (normalized === '/index.html') return '/';

    return normalized.replace(/\/index\.html$/i, '/');
}

function getRouteContext() {
    const rawPathname = window.location.pathname || '';
    const pathname = rawPathname.toLowerCase();
    const normalizedPath = normalizeRoutePath(rawPathname);
    const segments = normalizedPath.split('/').filter(Boolean).map(normalizeProductSlug);
    const normalizedSegments = segments.map(segment => segment.toLowerCase());
    const legacyHash = window.location.hash.replace('#', '').trim().toLowerCase();

    if (pathname.endsWith('/store.html')) return { page: 'store', view: 'store', legacy: true, legacyHash };
    if (pathname.endsWith('/account.html')) return { page: 'account', view: 'account', legacy: true, legacyHash };
    if (pathname.endsWith('/contact.html')) return { page: 'contact', view: 'contact', legacy: true, legacyHash };

    if (normalizedSegments[0] === 'products') {
        if (segments.length === 1) return { page: 'store', view: 'store', legacyHash };
        if (normalizedSegments[1] === 'cart') return { page: 'store', view: 'cart', legacyHash };
        if (normalizedSegments[1] === 'checkout') return { page: 'store', view: 'checkout', legacyHash };

        return { page: 'store', view: 'details', slug: segments[1], legacyHash };
    }

    if (normalizedSegments[0] === 'account') return { page: 'account', view: 'account', legacyHash };
    if (normalizedSegments[0] === 'contact') return { page: 'contact', view: 'contact', legacyHash };
    if (normalizedSegments[0] === 'terms') return { page: 'terms', view: 'terms', legacyHash };
    if (legacyHash === 'terms') return { page: 'home', view: 'terms', legacyHash };

    return { page: 'home', view: 'home', legacyHash };
}

function getCurrentStaticPageView() {
    return getRouteContext().page;
}

function isStorePage() {
    return getRouteContext().page === 'store';
}

function hasView(viewId) {
    return Boolean(document.getElementById(`view-${viewId}`));
}

function hasAccountUiContext() {
    return Boolean(
        document.getElementById('auth-form') ||
        document.getElementById('auth-guest-panel') ||
        document.querySelector('.orders-list')
    );
}

function buildStorePath(viewId, { category = '', productId = '' } = {}) {
    if (viewId === 'cart') return '/products/cart/';
    if (viewId === 'checkout') return '/products/checkout/';

    if (viewId === 'details') {
        const slug = getProductSlug(productId || localStorage.getItem('zarz_active_product'));
        return slug ? `/products/${slug}/` : STATIC_PAGE_ROUTES.store;
    }

    const url = new URL(STATIC_PAGE_ROUTES.store, window.location.origin);
    if (category && category !== 'all') {
        url.searchParams.set('category', category);
    }

    return `${url.pathname}${url.search}`;
}

function buildRoutePath(viewId, options = {}) {
    if (viewId === 'store' || viewId === 'cart' || viewId === 'checkout' || viewId === 'details') {
        return buildStorePath(viewId, options);
    }

    return STATIC_PAGE_ROUTES[viewId] || STATIC_PAGE_ROUTES.home;
}

function buildAbsoluteUrl(routePath) {
    return new URL(routePath, window.location.origin).toString();
}

function redirectToStaticPage(viewId, options = {}) {
    const targetUrl = new URL(buildRoutePath(viewId, options), window.location.origin);
    const targetPathAndSearch = normalizeRoutePath(targetUrl.pathname) + targetUrl.search;
    const currentPathAndSearch = normalizeRoutePath(window.location.pathname) + window.location.search;

    if (targetPathAndSearch === currentPathAndSearch) return;

    window.location.assign(targetUrl.toString());
}

function redirectToStore(options = {}) {
    redirectToStaticPage('store', options);
}

function setActiveStoreFilter(filter = 'all') {
    const filterItems = Array.from(document.querySelectorAll('.category-filter li'));
    if (!filterItems.length) return false;

    let matched = false;
    filterItems.forEach((item) => {
        const isActive = item.dataset.filter === filter;
        item.classList.toggle('active', isActive);
        if (isActive) matched = true;
    });

    if (!matched) {
        filterItems.forEach((item, index) => {
            item.classList.toggle('active', index === 0);
        });
    }

    return matched;
}

function applyStoreCategoryFromUrl() {
    if (!hasView('store')) return;

    const params = new URLSearchParams(window.location.search);
    const category = params.get('category');
    const searchInput = document.getElementById('service-search');

    if (searchInput) searchInput.value = '';
    if (!category || !setActiveStoreFilter(category)) {
        setActiveStoreFilter('all');
    }

    renderProducts(getFilteredProducts());
}

function sanitizeLettersOnly(value) {
    return String(value || '')
        .replace(/[^\p{L}\s]/gu, '')
        .replace(/\s{2,}/g, ' ')
        .replace(/^\s+/g, '');
}

function sanitizeDigitsOnly(value) {
    return String(value || '').replace(/\D+/g, '');
}

function sanitizeInputValue(value, mode) {
    if (mode === 'letters') return sanitizeLettersOnly(value);
    if (mode === 'digits') return sanitizeDigitsOnly(value);
    return String(value || '');
}

function sanitizeTrackedInput(input) {
    if (!input || !input.dataset) return;
    const mode = input.dataset.sanitize;
    if (!mode) return;

    const sanitizedValue = sanitizeInputValue(input.value, mode);
    if (input.value !== sanitizedValue) {
        input.value = sanitizedValue;
    }
}

function revealAppShell() {
    if (window.__zarzRevealFallback) {
        window.clearTimeout(window.__zarzRevealFallback);
        window.__zarzRevealFallback = null;
    }
}

function scheduleAppReveal(delay = 900) {
    if (window.__zarzRevealFallback) {
        window.clearTimeout(window.__zarzRevealFallback);
    }

    window.__zarzRevealFallback = window.setTimeout(() => {
        revealAppShell();
    }, delay);
}

function scheduleIdleTask(callback, timeout = 1200) {
    if (typeof callback !== 'function') return;

    if ('requestIdleCallback' in window) {
        window.requestIdleCallback(() => callback(), { timeout });
        return;
    }

    window.setTimeout(callback, timeout);
}

function scheduleFeaturedProductsRender() {
    const featContainer = document.getElementById('featured-container');
    if (!featContainer || featContainer.dataset.rendered === 'true') return;

    const render = () => {
        if (featContainer.dataset.rendered === 'true') return;
        featContainer.dataset.rendered = 'true';
        renderFeaturedProducts();
    };

    if (!('IntersectionObserver' in window)) {
        scheduleIdleTask(render, 1000);
        return;
    }

    const featuredShell = featContainer.closest('.featured-carousel-shell') || featContainer;
    const observer = new IntersectionObserver((entries) => {
        if (!entries.some((entry) => entry.isIntersecting)) return;
        observer.disconnect();
        render();
    }, { rootMargin: '260px 0px' });

    observer.observe(featuredShell);
    scheduleIdleTask(() => {
        observer.disconnect();
        render();
    }, 1800);
}

// Initialize App
document.addEventListener('DOMContentLoaded', async () => {
    appState.lang = 'ar';
    document.documentElement.lang = appState.lang;
    document.documentElement.dir = 'rtl';
    const currentPageView = getCurrentStaticPageView();
    const hasAccountUi = hasAccountUiContext();
    accountInitialLoadPending = hasAccountUi && currentPageView === 'account';
    accountOrdersLoadPending = false;
    shouldScrollAccountOrdersOnLoad = consumeAccountOrdersScroll();
    pendingGoogleRedirectOutcome = consumeGoogleRedirectOutcome();

    fetchExchangeRates();
    bindAuthStateEvents();
    if (hasAccountUi) {
        bindAccountAuthUI();
        updateAccountProfileUI();
    }
    initRouter();
    updateCartCount(false);
    flushPendingPostNavigationToast();
    if (hasAccountUi && !shouldDelayAccountUiUntilBootstrap()) {
        renderOrders();
    }

    const finalizeInitialAccountBootstrap = () => {
        if (!accountInitialLoadPending) return;
        accountInitialLoadPending = false;
        updateAccountProfileUI();
        renderOrders();
    };

    const bootstrapAuthState = async () => {
        if (window.zarzAuthStateReadyPromise) {
            try {
                const initialUser = await window.zarzAuthStateReadyPromise;
                await handleAuthStateChange(initialUser, { silent: true });
            } catch (error) {
                console.error(error);
                setAccountFeedback(ARABIC_UI_TEXT.authRequiredForSync, 'info');
            } finally {
                finalizeInitialAccountBootstrap();
            }
            return;
        }

        try {
            await handleAuthStateChange(window.zarzCurrentUser || null, { silent: true });
        } catch (error) {
            console.error(error);
        } finally {
            finalizeInitialAccountBootstrap();
        }
    };

    if (currentPageView === 'home') {
        scheduleFeaturedProductsRender();
    } else if (document.getElementById('featured-container')) {
        renderFeaturedProducts();
    }

    if (currentPageView === 'account' || currentPageView === 'checkout') {
        bootstrapAuthState();
    } else {
        scheduleIdleTask(() => {
            bootstrapAuthState();
        }, 900);
    }
    
    // Mobile Menu
    const mobileBtn = document.querySelector('.mobile-menu-btn');
    const navLinks = document.querySelector('.nav-links');
    if(mobileBtn && navLinks) {
        const setMobileMenuState = (isOpen) => {
            navLinks.classList.toggle('show-mobile-menu', isOpen);
            mobileBtn.classList.toggle('active', isOpen);
            document.body.classList.toggle('nav-open', isOpen && window.innerWidth <= 768);
        };

        mobileBtn.addEventListener('click', () => {
            setMobileMenuState(!navLinks.classList.contains('show-mobile-menu'));
        });
        
        // Close menu on link click
        navLinks.addEventListener('click', (e) => {
             if (e.target.closest('a') || e.target.closest('button')) {
                 setMobileMenuState(false);
             }
        });

        document.addEventListener('click', (e) => {
            if (!navLinks.classList.contains('show-mobile-menu')) return;
            if (e.target.closest('.navbar')) return;
            setMobileMenuState(false);
        });

        window.addEventListener('resize', () => {
            if (window.innerWidth > 768) {
                setMobileMenuState(false);
            }
        });

        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                setMobileMenuState(false);
            }
        });
    }

// Currency dropdown removed

    // Search & Filter
    const serviceSearch = document.getElementById('service-search');
    if (serviceSearch) {
        const runStoreSearch = debounce(() => {
            renderProducts(getFilteredProducts());
        }, 90);

        serviceSearch.addEventListener('input', runStoreSearch);

        document.querySelectorAll('.category-filter li').forEach(li => {
            li.addEventListener('click', (e) => {
                const targetLi = e.target.closest('li');
                if(!targetLi) return;
                document.querySelectorAll('.category-filter li').forEach(el => el.classList.remove('active'));
                targetLi.classList.add('active');
                const filter = targetLi.dataset.filter;
                serviceSearch.value = '';

                renderProducts(getFilteredProducts(filter, ''));
            });
        });

        applyStoreCategoryFromUrl();
    }

    // -- Form Persistence Setup --
    const restoreCheckout = () => {
        const savedCheckout = safeJsonParse('zarz_checkout', {});
        const nameInput = document.getElementById('checkout-name');
        const phoneInput = document.getElementById('checkout-phone');
        const paymentMethodInput = document.getElementById('checkout-payment-method');
        const transactionLast4Input = document.getElementById('checkout-transaction-last4');

        if (savedCheckout.name && nameInput) nameInput.value = savedCheckout.name;
        if (savedCheckout.phone && phoneInput) phoneInput.value = savedCheckout.phone;
        if (savedCheckout.paymentMethod && paymentMethodInput) paymentMethodInput.value = savedCheckout.paymentMethod;
        if (savedCheckout.transactionLast4 && transactionLast4Input) transactionLast4Input.value = savedCheckout.transactionLast4;

        sanitizeTrackedInput(nameInput);
        sanitizeTrackedInput(phoneInput);
    };
    
    restoreCheckout();

    const updateCheckoutPaymentUI = () => {
        const methodSelect = document.getElementById('checkout-payment-method');
        const bankPanel = document.getElementById('bank-transfer-panel');
        const last4Input = document.getElementById('checkout-transaction-last4');
        const submitBtn = document.getElementById('checkout-submit-btn') || document.querySelector('#checkoutForm button[type="submit"]');
        const selectedMethod = methodSelect ? methodSelect.value : '';

        if (bankPanel) bankPanel.hidden = selectedMethod !== 'bankak';
        if (last4Input) {
            last4Input.required = selectedMethod === 'bankak';
            if (selectedMethod !== 'bankak') last4Input.value = '';
        }
        if (submitBtn) {
            const label = submitBtn.querySelector('[data-i18n="checkout_submit_btn"], [data-i18n="checkout_wa_btn"]');
            const icon = submitBtn.querySelector('i');
            if (selectedMethod === 'bankak') {
                submitBtn.style.background = '#0ea5e9';
                submitBtn.style.boxShadow = '0 4px 15px rgba(14, 165, 233, 0.28)';
                if (icon) icon.className = 'fa-solid fa-building-columns';
                if (label) label.textContent = t('Confirm Bank Transfer Order', 'تأكيد طلب التحويل البنكي');
            } else {
                submitBtn.style.background = '#25D366';
                submitBtn.style.boxShadow = '0 4px 15px rgba(37, 211, 102, 0.3)';
                if (icon) icon.className = 'fa-solid fa-paper-plane';
                if (label) label.textContent = t('Confirm and Send Order', 'تأكيد الطلب وإرساله');
            }
        }
    };

    const saveCheckout = createBufferedTask(() => {
        const nameInput = document.getElementById('checkout-name');
        const phoneInput = document.getElementById('checkout-phone');
        const paymentMethodInput = document.getElementById('checkout-payment-method');
        const transactionLast4Input = document.getElementById('checkout-transaction-last4');
        const name = nameInput ? nameInput.value : '';
        const phone = phoneInput ? phoneInput.value : '';
        const paymentMethod = paymentMethodInput ? paymentMethodInput.value : '';
        const transactionLast4 = transactionLast4Input ? transactionLast4Input.value : '';
        localStorage.setItem('zarz_checkout', JSON.stringify({ name, phone, paymentMethod, transactionLast4 }));
    }, 160);

    const checkoutForm = document.getElementById('checkoutForm');
    if(checkoutForm) {
        checkoutForm.addEventListener('input', saveCheckout);
        checkoutForm.addEventListener('change', saveCheckout);
    }
    updateCheckoutPaymentUI();
    const paymentMethodSelect = document.getElementById('checkout-payment-method');
    if(paymentMethodSelect) {
        paymentMethodSelect.addEventListener('change', updateCheckoutPaymentUI);
    }

    document.addEventListener('input', (event) => {
        const target = event.target;
        if (!(target instanceof HTMLInputElement)) return;
        sanitizeTrackedInput(target);
    });

    const detailsContainer = document.getElementById('details-container');
    const scheduleDetailsSave = createBufferedTask(() => {
        if(window.saveDetailsState) window.saveDetailsState();
    }, 160);

    if (detailsContainer) {
        detailsContainer.addEventListener('input', scheduleDetailsSave);
        detailsContainer.addEventListener('change', scheduleDetailsSave);
    }
    document.addEventListener('keydown', (event) => {
        if (event.key === 'Escape') closeQuickView();
    });
});

window.saveDetailsState = function() {
    let state = {};
    const extract = (id) => { const el = document.getElementById(id); if(el) state[id] = el.value; };
    ['target-link', 'detail-qty', 'game-country', 'player-id', 'game-package', 'target-email', 'web-req', 'ref-link'].forEach(extract);
    localStorage.setItem('zarz_details_form', JSON.stringify(state));
};

window.restoreDetailsState = function() {
    let state = safeJsonParse('zarz_details_form', {});
    let trigPkg = null;
    let trigQty = false;
    Object.keys(state).forEach(id => {
        const el = document.getElementById(id);
        if(el) {
            el.value = state[id];
            if(id === 'detail-qty') trigQty = true;
            if(id === 'game-package') trigPkg = el;
        }
    });
    if(trigPkg) trigPkg.dispatchEvent(new Event('change', {bubbles: true}));
    else if(trigQty) updateDetailQty(0);
};


// Exchange Rates setup
function fetchExchangeRates() {
    appState.exchangeRates = {
        SAR: 1,
        SDG: 940,
        USD: 940 / 3500,
        EGP: 940 / 73,
        AED: 940 / 942
    };
    appState.currency = 'SDG'; // Enforce SDG securely
    localStorage.setItem('zarz_currency', 'SDG');
    refreshPrices();
}

// Pricing formatting
function formatPrice(sarPrice) {
    const rate = appState.exchangeRates[appState.currency] || 1;
    const converted = sarPrice * rate;
    const symbol = appState.currencySymbols[appState.currency];
    return `${converted.toFixed(2)} ${symbol}`;
}

function refreshPrices() {
    document.querySelectorAll('[data-price-sar]').forEach(el => {
        const sarValue = parseFloat(el.getAttribute('data-price-sar'));
        el.textContent = formatPrice(sarValue);
    });
}

function updateSeoMeta(viewId) {
    const descriptionMeta = document.querySelector('meta[name="description"]');
    const canonicalLink = document.querySelector('link[rel="canonical"]');
    const ogTitleMeta = document.querySelector('meta[property="og:title"]');
    const ogDescriptionMeta = document.querySelector('meta[property="og:description"]');
    const ogUrlMeta = document.querySelector('meta[property="og:url"]');
    const twitterTitleMeta = document.querySelector('meta[name="twitter:title"]');
    const twitterDescriptionMeta = document.querySelector('meta[name="twitter:description"]');
    const brandTitle = 'زارز | ZARZ';

    const seoByView = {
        home: {
            title: 'زارز | ZARZ - متجر الخدمات الرقمية، شحن الألعاب والاشتراكات',
            description: 'زارز أوفشال يقدم خدمات رقمية احترافية تشمل شحن الألعاب، تنمية حسابات التواصل الاجتماعي، الاشتراكات الذكية، وتطوير المتاجر والمواقع بسرعة مع دعم فني متواصل.'
        },
        store: {
            title: `المنتجات | ${brandTitle}`,
            description: 'تصفح جميع منتجات وخدمات زارز أوفشال عبر صفحة منتجات حقيقية قابلة للأرشفة والفهرسة.'
        },
        cart: {
            title: `السلة | ${brandTitle}`,
            description: 'راجع منتجاتك المختارة داخل سلة زارز أوفشال وأكمل الطلب بسهولة.'
        },
        checkout: {
            title: `إتمام الطلب | ${brandTitle}`,
            description: 'أكمل طلبك في زارز أوفشال عبر صفحة دفع ومتابعة واضحة.'
        },
        contact: {
            title: `تواصل معنا | ${brandTitle}`,
            description: 'تواصل مع فريق زارز أوفشال عبر صفحة مستقلة تحتوي على وسائل التواصل والنموذج المباشر.'
        },
        account: {
            title: `حسابي | ${brandTitle}`,
            description: 'تابع طلباتك الأخيرة في زارز أوفشال من صفحة مستقلة وسهلة التصفح.'
        },
        terms: {
            title: `شروط الاستخدام | ${brandTitle}`,
            description: 'اطلع على شروط الاستخدام وسياسات الطلب والدفع في زارز أوفشال.'
        }
    };

    let seo = seoByView[viewId] || seoByView.home;
    let seoUrl = buildAbsoluteUrl(buildRoutePath(viewId));

    if (viewId === 'details') {
        const activeProductId = localStorage.getItem('zarz_active_product');
        const product = products.find(p => p.id === activeProductId);
        if (product) {
            const productCopy = getProductCopy(product);
            const cleanDescription = String(productCopy.desc || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
            seo = {
                title: `${productCopy.title} | ${brandTitle}`,
                description: cleanDescription || seoByView.store.description
            };
            seoUrl = buildAbsoluteUrl(buildRoutePath('details', { productId: product.id }));
        }
    } else if (viewId === 'store' && isStorePage()) {
        seoUrl = window.location.origin + normalizeRoutePath(window.location.pathname) + window.location.search;
    }

    document.title = seo.title;
    if (descriptionMeta) descriptionMeta.setAttribute('content', seo.description);
    if (canonicalLink) canonicalLink.setAttribute('href', seoUrl);
    if (ogTitleMeta) ogTitleMeta.setAttribute('content', seo.title);
    if (ogDescriptionMeta) ogDescriptionMeta.setAttribute('content', seo.description);
    if (ogUrlMeta) ogUrlMeta.setAttribute('content', seoUrl);
    if (twitterTitleMeta) twitterTitleMeta.setAttribute('content', seo.title);
    if (twitterDescriptionMeta) twitterDescriptionMeta.setAttribute('content', seo.description);
}

// Navigation / Router
function navigateTo(viewId, options = {}) {
    const currentDomEvent = typeof event !== 'undefined' ? event : null;
    if (currentDomEvent && typeof currentDomEvent.preventDefault === 'function') {
        currentDomEvent.preventDefault();
    }

    const currentPageView = getCurrentStaticPageView();
    const directPageViews = new Set(['home', 'store', 'account', 'contact', 'terms']);
    const storeOnlyViews = new Set(['details', 'cart', 'checkout']);

    if (directPageViews.has(viewId) && (currentPageView !== viewId || !hasView(viewId))) {
        redirectToStaticPage(viewId, options);
        return;
    }

    if (storeOnlyViews.has(viewId) && (!isStorePage() || !hasView(viewId))) {
        redirectToStaticPage(viewId, options);
        return;
    }

    const targetView = document.getElementById('view-' + viewId);
    if (!targetView) return;

    localStorage.setItem('zarz_view', viewId);

    const routePath = buildRoutePath(viewId, {
        category: options.category,
        productId: options.productId
    });
    const targetUrl = new URL(routePath, window.location.origin);
    const currentPathAndSearch = normalizeRoutePath(window.location.pathname) + window.location.search;
    const targetPathAndSearch = normalizeRoutePath(targetUrl.pathname) + targetUrl.search;

    if (!options.skipHistory && currentPathAndSearch !== targetPathAndSearch) {
        window.history.pushState(null, '', targetPathAndSearch);
    }
    
    document.querySelectorAll('.view').forEach(view => view.classList.remove('active'));
    document.querySelectorAll('.nav-link').forEach(link => link.classList.remove('active'));

    targetView.classList.add('active');

    const originalScrollBehavior = document.documentElement.style.scrollBehavior;
    document.documentElement.style.scrollBehavior = 'auto';
    window.scrollTo(0, 0);
    document.documentElement.style.scrollBehavior = originalScrollBehavior;

    const navTargetView = viewId === 'details' ? 'store' : viewId;
    const navLink = document.querySelector('.nav-link[data-view="' + navTargetView + '"]');
    if (navLink) navLink.classList.add('active');

    if (viewId === 'store') {
        if (typeof options.category !== 'undefined') {
            setActiveStoreFilter(options.category || 'all');
        } else {
            applyStoreCategoryFromUrl();
        }
        renderProducts(getFilteredProducts());
    }
    if (viewId === 'cart' || viewId === 'checkout') renderCart();

    updateSeoMeta(viewId);
}

// To use from hero buttons
function filterStore(cat) {
    if (!isStorePage() || !hasView('store')) {
        redirectToStore({ category: cat });
        return;
    }

    const searchInput = document.getElementById('service-search');
    if (searchInput) searchInput.value = '';

    navigateTo('store', { category: cat || 'all' });
    renderProducts(getFilteredProducts(cat || 'all', ''));
}

function initRouter() {
    const routeContext = getRouteContext();
    const legacyHash = String(routeContext.legacyHash || '').toLowerCase();

    if (routeContext.legacy) {
        if (routeContext.page === 'store') {
            if (legacyHash === 'cart') {
                redirectToStaticPage('cart');
                return;
            }
            if (legacyHash === 'checkout') {
                redirectToStaticPage('checkout');
                return;
            }
            if (legacyHash === 'details') {
                const activeProductId = localStorage.getItem('zarz_active_product');
                if (activeProductId && products.find(product => product.id === activeProductId)) {
                    redirectToStaticPage('details', { productId: activeProductId });
                    return;
                }
            }
        }

        redirectToStaticPage(routeContext.page);
        return;
    }

    if (legacyHash) {
        if (legacyHash === 'home') {
            redirectToStaticPage('home');
            return;
        }
        if (legacyHash === 'store') {
            redirectToStaticPage('store');
            return;
        }
        if (legacyHash === 'account') {
            redirectToStaticPage('account');
            return;
        }
        if (legacyHash === 'contact') {
            redirectToStaticPage('contact');
            return;
        }
        if (legacyHash === 'terms') {
            redirectToStaticPage('terms');
            return;
        }
        if (legacyHash === 'cart') {
            redirectToStaticPage('cart');
            return;
        }
        if (legacyHash === 'checkout') {
            redirectToStaticPage('checkout');
            return;
        }
        if (legacyHash === 'details') {
            const activeProductId = localStorage.getItem('zarz_active_product');
            if (activeProductId && products.find(product => product.id === activeProductId)) {
                redirectToStaticPage('details', { productId: activeProductId });
                return;
            }
            redirectToStaticPage('store');
            return;
        }
    }

    if (routeContext.view === 'details') {
        const productId = getProductIdBySlug(routeContext.slug);
        if (!productId) {
            redirectToStaticPage('store');
            return;
        }

        const canonicalDetailsPath = buildStorePath('details', { productId });
        const canonicalPathname = normalizeRoutePath(new URL(canonicalDetailsPath, window.location.origin).pathname);
        const currentPathname = normalizeRoutePath(window.location.pathname);

        if (canonicalPathname !== currentPathname) {
            window.history.replaceState({}, '', buildAbsoluteUrl(canonicalDetailsPath));
        }

        viewDetails(productId);
        return;
    }

    if (!hasView(routeContext.view)) {
        const fallbackView = hasView(routeContext.page) ? routeContext.page : 'home';
        navigateTo(fallbackView, { skipHistory: true });
        return;
    }

    if (routeContext.view === 'store') {
        const category = new URLSearchParams(window.location.search).get('category') || 'all';
        navigateTo('store', { category, skipHistory: true });
        return;
    }

    navigateTo(routeContext.view, { skipHistory: true });
}

window.addEventListener('popstate', () => {
    initRouter();
});

window.addEventListener('hashchange', () => {
    initRouter();
});

